#!/bin/bash
# ╔═══════════════════════════════════════════════════════════════╗
# ║  ED-CCG 多模型协作工作流 - 一键安装 (Mac / Linux)               ║
# ║  Claude 编排 + Codex (后端) + Gemini (前端)                    ║
# ║  使用方式: bash setup.sh                                       ║
# ╚═══════════════════════════════════════════════════════════════╝

set -e
ED_CCG_HOME="$HOME/.ed-ccg"

echo ""
echo "╔═══════════════════════════════════════════════════╗"
echo "║  ED-CCG 多模型协作工作流 - 安装中...                ║"
echo "╚═══════════════════════════════════════════════════╝"
echo ""

mkdir -p "$ED_CCG_HOME"/{workflows,prompts/codex,prompts/gemini}


# --- workflows/ed-ccg-analyze.md ---
echo '' | base64 -d > "$ED_CCG_HOME/workflows/ed-ccg-analyze.md"

# --- workflows/ed-ccg-commit.md ---
echo '' | base64 -d > "$ED_CCG_HOME/workflows/ed-ccg-commit.md"

# --- workflows/ed-ccg-debug.md ---
echo '' | base64 -d > "$ED_CCG_HOME/workflows/ed-ccg-debug.md"

# --- workflows/ed-ccg-execute.md ---
echo '' | base64 -d > "$ED_CCG_HOME/workflows/ed-ccg-execute.md"

# --- workflows/ed-ccg-feat.md ---
echo '' | base64 -d > "$ED_CCG_HOME/workflows/ed-ccg-feat.md"

# --- workflows/ed-ccg-plan.md ---
echo '' | base64 -d > "$ED_CCG_HOME/workflows/ed-ccg-plan.md"

# --- workflows/ed-ccg-review.md ---
echo '' | base64 -d > "$ED_CCG_HOME/workflows/ed-ccg-review.md"

# --- workflows/ed-ccg-workflow.md ---
echo '' | base64 -d > "$ED_CCG_HOME/workflows/ed-ccg-workflow.md"

# --- prompts/codex/analyzer.md ---
echo '' | base64 -d > "$ED_CCG_HOME/prompts/codex/analyzer.md"

# --- prompts/codex/architect.md ---
echo '' | base64 -d > "$ED_CCG_HOME/prompts/codex/architect.md"

# --- prompts/codex/reviewer.md ---
echo '' | base64 -d > "$ED_CCG_HOME/prompts/codex/reviewer.md"

# --- prompts/codex/tester.md ---
echo '' | base64 -d > "$ED_CCG_HOME/prompts/codex/tester.md"

# --- prompts/gemini/analyzer.md ---
echo '' | base64 -d > "$ED_CCG_HOME/prompts/gemini/analyzer.md"

# --- prompts/gemini/architect.md ---
echo '' | base64 -d > "$ED_CCG_HOME/prompts/gemini/architect.md"

# --- prompts/gemini/frontend.md ---
echo '' | base64 -d > "$ED_CCG_HOME/prompts/gemini/frontend.md"

# --- prompts/gemini/reviewer.md ---
echo '' | base64 -d > "$ED_CCG_HOME/prompts/gemini/reviewer.md"

# --- prompts/gemini/tester.md ---
echo '' | base64 -d > "$ED_CCG_HOME/prompts/gemini/tester.md"

# --- install.sh ---
echo '' | base64 -d > "$ED_CCG_HOME/install.sh"

# --- README.md ---
echo '' | base64 -d > "$ED_CCG_HOME/README.md"
chmod +x "$ED_CCG_HOME/install.sh"

# === 自动配置 shell alias ===
ALIAS_LINE='alias edccg-init="~/.ed-ccg/install.sh"'
SHELL_RC=""

if [ -n "$ZSH_VERSION" ] || [ "$SHELL" = "/bin/zsh" ] || [ -f "$HOME/.zshrc" ]; then
  SHELL_RC="$HOME/.zshrc"
elif [ -f "$HOME/.bashrc" ]; then
  SHELL_RC="$HOME/.bashrc"
elif [ -f "$HOME/.bash_profile" ]; then
  SHELL_RC="$HOME/.bash_profile"
fi

if [ -n "$SHELL_RC" ]; then
  if ! grep -q "edccg-init" "$SHELL_RC" 2>/dev/null; then
    echo "" >> "$SHELL_RC"
    echo "# ED-CCG 多模型协作工作流" >> "$SHELL_RC"
    echo "$ALIAS_LINE" >> "$SHELL_RC"
    echo "🔧 已添加 alias 到 $SHELL_RC"
    echo "   运行 source $SHELL_RC 或重开终端生效"
  else
    echo "🔧 alias 已存在于 $SHELL_RC"
  fi
else
  echo "⚠️  未找到 shell 配置文件，请手动添加："
  echo "   $ALIAS_LINE"
fi

echo ""
echo "✅ ED-CCG 安装完成！"
echo ""
echo "📁 位置: $ED_CCG_HOME"
echo ""
echo "📋 使用方式:"
echo "   edccg-init                   # 在当前项目安装工作流"
echo "   edccg-init /path/to/project  # 指定项目安装"
echo ""
echo "🎮 可用命令 (Antigravity 中使用 Claude 模型):"
echo "   /ed-ccg-workflow  /ed-ccg-plan     /ed-ccg-execute"
echo "   /ed-ccg-review    /ed-ccg-feat     /ed-ccg-commit"
echo "   /ed-ccg-debug     /ed-ccg-analyze"
echo ""
